var e=[{id:`L3_1`,type:`narration`,speaker:null,text:{KOREA:`어린 시절, 우리 가족은 사람이 없는 깊은 산 속으로 들어갔다.`,JPN:`幼い頃、僕の家族は人が誰もいない、深い山奥に移り住んだ。`,ENG:`When I was young, our family fled deep into the mountains.`,TWN:`小時候，我和家人住進了沒有人煙的深山裡。`},stage:{bg:`SNOWYARD_01`,slots:{L:null,C:null,R:null}}},{id:`L4_1`,type:`narration`,speaker:null,text:{KOREA:`전쟁을 피해. 번뇌를 피해.`,JPN:`戦争から、煩悩から逃れるために。`,ENG:`We fled from the war. We fled from agony.`,TWN:`為了避開戰爭，避開煩惱。`},stage:{bg:`SNOWYARD_01`,slots:{L:null,C:null,R:null}}},{id:`L5_1`,type:`narration`,speaker:null,text:{KOREA:`그리고 핏줄에 얽힌 주박을 피해.`,JPN:`そして血筋に刻まれた呪縛から逃れるために。`,ENG:`And from the bounds of our bloodline.`,TWN:`還有避開糾纏於血脈之中的束縛。`},stage:{bg:`SNOWYARD_01`,slots:{L:null,C:null,R:null}}},{id:`L6_1`,type:`narration`,speaker:null,text:{KOREA:`때때로 정신이 온전한 날이면 어머니는 마루에 앉아 눈 내리는 하늘을 올려다보셨고.`,JPN:`時々精神が正気に戻ると、母さんは床に座って雪が降る空を見上げていて。`,ENG:`Whenever my mother was back to her senses, she would sit on the wooden floor and look up at the snowing sky.`,TWN:`母親在偶爾清醒的日子裡，會坐在廊簷下，仰望著落雪的天空。`},stage:{bg:`SNOWYARD_01`,slots:{L:null,C:null,R:null}}},{id:`L7_1`,type:`narration`,speaker:null,text:{KOREA:`나는 기둥 뒤에 숨어 그 야윈 등을 멀리서 바라보았다.`,JPN:`僕は柱の裏に隠れて、その瘦せこけた背中を遠くから見つめていた。`,ENG:`I would hide behind the pillars and watch her scrawny, bony back from afar.`,TWN:`我就躲在柱子的後面，遠遠地望著母親瘦削的背影。`},stage:{bg:`SNOWYARD_01`,slots:{L:null,C:null,R:null}}},{id:`L8_1`,type:`narration`,speaker:null,text:{KOREA:`바라만 볼 수밖에 없었다.`,JPN:`見つめることしかできなかった。`,ENG:`That was the only thing I could do.`,TWN:`我只能遠遠地望著。`},stage:{bg:`SNOWYARD_01`,slots:{L:null,C:null,R:null}}},{id:`L11_1`,type:`dialog`,speaker:`JOOSHIYOON_FENRIR_CA_NULL`,text:{KOREA:`미나 양……?`,JPN:`ミナさん……？`,ENG:`Mina...?`,TWN:`米娜……？`},stage:{bg:`COUNTERSIDE_PLAIN`,slots:{L:{char_id:`JOOSHIYOON_FENRIR_CA_NULL`,face:`UNIT_SURPRISE`},C:null,R:null}}},{id:`L12_1`,type:`dialog`,speaker:`YOOMINA_FENRIR_NEXT_NULL`,text:{KOREA:`선배? 깨어났구나!`,JPN:`先輩？　目が覚めたんだね！`,ENG:`Shiyoon? You’re awake!`,TWN:`前輩？你醒了！`},stage:{bg:`COUNTERSIDE_PLAIN`,slots:{L:{char_id:`JOOSHIYOON_FENRIR_CA_NULL`,face:`UNIT_SURPRISE`},C:null,R:{char_id:`YOOMINA_FENRIR_NEXT_NULL`,face:`UNIT_LAUGH`}}}},{id:`L14_1`,type:`dialog`,speaker:`SEO_YOON_ALT_CA_NULL`,text:{KOREA:`정신이 들어, 시윤 선배? 몸은 좀 어때?`,JPN:`気が付いた、アキヤマ先輩？　身体の調子はどう？`,ENG:`How are you feeling, Shiyoon? Any pain?`,TWN:`你醒了，時雲前輩？感覺身體怎麼樣？`},stage:{bg:`COUNTERSIDE_PLAIN`,slots:{L:null,C:{char_id:`SEO_YOON_ALT_CA_NULL`,face:`UNIT_LAUGH`},R:null}}},{id:`L17_1`,type:`dialog`,speaker:`JOOSHIYOON_FENRIR_CA_NULL`,text:{KOREA:`으음……. 네. 괜찮은 것 같네요.`,JPN:`うーん……はい。大丈夫そうです。`,ENG:`Mmm... Yes. I'm fine, I think.`,TWN:`呃嗯……嗯，好像沒事了。`},stage:{bg:`COUNTERSIDE_PLAIN`,slots:{L:{char_id:`JOOSHIYOON_FENRIR_CA_NULL`,face:`UNIT_DESPAIR`},C:null,R:{char_id:`YOOMINA_FENRIR_NEXT_NULL`,face:`UNIT_LAUGH`}}}},{id:`L18_1`,type:`dialog`,speaker:`JOOSHIYOON_FENRIR_CA_NULL`,text:{KOREA:`그러니 이제 업어 주시진 않아도 됩니다.`,JPN:`ですから、もう背負ってもらわなくても大丈夫です。`,ENG:`You can stop carrying me now.`,TWN:`你不用背著我也行。`},stage:{bg:`COUNTERSIDE_PLAIN`,slots:{L:{char_id:`JOOSHIYOON_FENRIR_CA_NULL`,face:`UNIT_LAUGH`},C:null,R:{char_id:`YOOMINA_FENRIR_NEXT_NULL`,face:`UNIT_LAUGH`}}}},{id:`L19_1`,type:`dialog`,speaker:`YOOMINA_FENRIR_NEXT_NULL`,text:{KOREA:`어, 어어. 응. 미안.`,JPN:`あ、ああ。うん。ごめん。`,ENG:`O-oh, right. Sorry about that.`,TWN:`喔，喔喔，對不起……`},stage:{bg:`COUNTERSIDE_PLAIN`,slots:{L:{char_id:`JOOSHIYOON_FENRIR_CA_NULL`,face:`UNIT_LAUGH`},C:null,R:{char_id:`YOOMINA_FENRIR_NEXT_NULL`,face:`UNIT_SURPRISE`}}}},{id:`L21_1`,type:`dialog`,speaker:`JOOSHIYOON_FENRIR_CA_NULL`,text:{KOREA:`그나저나 제가 얼마나 기절해 있었던 거죠?`,JPN:`ところで、僕はどれくらい気絶していたんですか？`,ENG:`Anyway, how long was I out?`,TWN:`對了，我昏迷多久了？`},stage:{bg:`COUNTERSIDE_PLAIN`,slots:{L:null,C:{char_id:`JOOSHIYOON_FENRIR_CA_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L22_1`,type:`dialog`,speaker:`YOOMINA_FENRIR_NEXT_NULL`,text:{KOREA:`잘 모르겠어. 꽤 오랫동안이었지, 아마.`,JPN:`よくわからない。随分長かったかな、たぶん。`,ENG:`I'm not sure. Quite some time, probably.`,TWN:`不知道，很久了吧，大概。`},stage:{bg:`COUNTERSIDE_PLAIN`,slots:{L:null,C:{char_id:`YOOMINA_FENRIR_NEXT_NULL`,face:`UNIT_DESPAIR`},R:null}}},{id:`L25_1`,type:`dialog`,speaker:`SEO_YOON_ALT_CA_NULL`,text:{KOREA:`어쨌든 일어나서 다행이야.`,JPN:`とにかく起きてくれてよかったわ。`,ENG:`I'm just glad that you're up again.`,TWN:`不管怎樣，你能醒過來就好。`},stage:{bg:`COUNTERSIDE_PLAIN`,slots:{L:{char_id:`YOOMINA_FENRIR_NEXT_NULL`,face:`UNIT_SURPRISE`},C:null,R:{char_id:`SEO_YOON_ALT_CA_NULL`,face:`UNIT_LAUGH`}}}},{id:`L26_1`,type:`dialog`,speaker:`SEO_YOON_ALT_CA_NULL`,text:{KOREA:`미나가 선배 안 일어나면 어떡하냐고 계속 안절부절못했거든.`,JPN:`ミナが、先輩が目を覚ましてくれなかったらどうしようって、すごく心配していたからね。`,ENG:`Mina almost lost it, worrying over you not waking up.`,TWN:`米娜一直很擔心你啦，說前輩醒不過來該怎麼辦。`},stage:{bg:`COUNTERSIDE_PLAIN`,slots:{L:{char_id:`YOOMINA_FENRIR_NEXT_NULL`,face:`UNIT_SURPRISE`},C:null,R:{char_id:`SEO_YOON_ALT_CA_NULL`,face:`UNIT_IDLE`}}}}];export{e as default};